using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — HttpClient and ILogger are constructor-injected by the DI container.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Retrieve a resource by its unique identifier.")]
    public async Task<string> GetResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search resources by a query string. Returns matching results as JSON.")]
    public async Task<string> SearchResources(
        [Description("Search query to filter resources")] string query,
        [Description("Maximum number of results to return (1-100)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching resources: {Query} (limit {Limit})", query, limit);
        var response = await httpClient.GetAsync(
            $"/api/resources?q={Uri.EscapeDataString(query)}&limit={limit}",
            cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new resource with the given name and content.")]
    public async Task<string> CreateResource(
        [Description("Display name for the new resource")] string name,
        [Description("Body content of the resource")] string content,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating resource: {Name}", name);
        var payload = JsonSerializer.Serialize(new { name, content }, JsonOptions);
        var response = await httpClient.PostAsync(
            "/api/resources",
            new StringContent(payload, System.Text.Encoding.UTF8, "application/json"),
            cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

